insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('rlaif', 'RLAIF', 'Reinforcement Learning from AI Feedback', '“R-L-A-I-F”', ARRAY['rlaif','reinforcement learning from ai feedback']::text[], 'Rising', 'Like RLHF, but another AI does the rating instead of humans, to save time and money.', 'Like grading a mountain of essays with a well-trained teaching assistant instead of the professor — faster, cheaper, and mostly consistent.', 'Instead of paying labelers to rank thousands of answers, a strong model scores them against a rubric and those scores train the target model.', '[{"text":"The human version is RLHF.","id":"rlhf"},{"text":"Often paired with Constitutional AI.","id":"constitutionalai"},{"text":"Trains a reward model.","id":"rewardmodel"}]'::jsonb, 'RLAIF swaps human preference labels for judgments from an AI, often a larger model applying a written set of principles. It scales feedback far beyond what human raters could produce and cuts cost dramatically. The obvious risk is circularity: the student inherits the judge’s biases and blind spots, so a flawed evaluator quietly teaches flawed taste.', 'A way to scale alignment cheaply — but you’ve outsourced your taste to another model, flaws and all.', 'RLHF pipeline with an AI evaluator (often guided by a principles rubric) generating the preference signal.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('rewardmodel', 'Reward model', '', '', ARRAY['reward model','preference model','rm']::text[], 'Core', 'A model trained to score answers the way humans would, so it can grade at scale during training.', 'Like teaching a judge your taste from a stack of ranked examples, then letting that judge score thousands more while you sleep.', 'Labelers rank a few thousand answer-pairs; a reward model learns from them and then rates millions of the LLM’s attempts.', '[{"text":"The engine inside RLHF.","id":"rlhf"},{"text":"Trained on preference data.","id":"preferencedata"},{"text":"Avoided by DPO.","id":"dpo"}]'::jsonb, 'The reward model turns scattered human preferences into a single differentiable score the main model can optimize against. It’s the linchpin of RLHF — the policy chases higher reward. Its weakness is reward hacking: the model finds answers that score well without actually being good, because the reward model is an imperfect stand-in for real human judgment.', 'The frozen proxy for “what humans want”; if it’s miscalibrated, the whole tuned model drifts toward its blind spots.', 'A learned scalar scorer over responses, trained on preference pairs; the objective the RL policy optimizes.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('preferencedata', 'Preference data', '', '', ARRAY['preference data','preference pairs','comparison data']::text[], 'Core', 'Human (or AI) judgments of “this answer is better than that one,” used to teach models taste.', 'Like A/B taste tests: you don’t score each dish alone, you just say which of two you’d rather eat.', 'A labeler sees two model replies to the same question and marks the clearer, more helpful one as preferred.', '[{"text":"Trains a reward model.","id":"rewardmodel"},{"text":"Consumed directly by DPO.","id":"dpo"},{"text":"Gathered via HITL.","id":"hitl"}]'::jsonb, 'Rather than absolute scores, preference data captures relative rankings between responses, which humans give far more reliably than numeric grades. This pairwise signal trains reward models and drives methods like DPO. Its quality is everything: inconsistent, rushed, or biased comparisons teach the model the wrong preferences with perfect efficiency.', 'The raw material of alignment — the model’s manners are only as good as these comparisons.', 'Pairwise/ranked response comparisons; the training signal for reward models and preference-optimization losses.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('dpo', 'DPO', 'Direct Preference Optimization', '“D-P-O”', ARRAY['dpo','direct preference optimization']::text[], 'Rising', 'A simpler alternative to RLHF that tunes on preferences directly, skipping the separate reward model.', 'Like learning to cook straight from “diners preferred dish A over B” feedback, without first hiring a critic to translate it into scores.', 'A team fine-tunes on ranked answer-pairs with DPO and gets aligned behavior without standing up a reward model and RL loop.', '[{"text":"A leaner substitute for RLHF.","id":"rlhf"},{"text":"Skips the reward model.","id":"rewardmodel"},{"text":"Trained on preference data.","id":"preferencedata"}]'::jsonb, 'DPO reframes preference learning as a single classification-style loss on the pairs, mathematically implying the reward instead of training one explicitly. That removes the fragile, moving-parts RL pipeline (reward model plus PPO) and is more stable and easier to run. The trade-off: less flexible than full RL for some objectives, and still bounded by the quality of the preference data.', 'Why alignment got cheaper and more teams can do it — fewer moving parts than classic RLHF.', 'Closed-form preference loss that optimizes the policy directly on pairs, implicitly encoding the reward; no separate RM/PPO.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('constitutionalai', 'Constitutional AI', 'Constitutional AI', '“C-A-I”', ARRAY['constitutional ai','cai']::text[], 'Rising', 'Aligning a model against a written set of principles instead of case-by-case human labels.', 'Like giving an employee a clear code of conduct and letting them self-correct against it, rather than a manager approving every single action.', 'A model critiques and revises its own answers against rules like “be helpful but don’t assist harm,” and those revisions train the final model.', '[{"text":"A structured form of RLAIF.","id":"rlaif"},{"text":"An approach to alignment.","id":"alignment"}]'::jsonb, 'Constitutional AI, introduced by Anthropic, writes down explicit principles (a “constitution”) and has the model use them to critique and improve its own outputs, generating training data with minimal human labeling. It makes the values steering the model explicit and auditable, and scales better than hand-labeling every case. It still depends on the wisdom of the principles and the model’s ability to apply them faithfully.', 'Values you can read and revise, not buried in opaque labels — useful when you need to explain why a model behaves as it does.', 'Self-critique/revision against a written principle set to generate alignment data; a structured form of AI feedback.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('instructiontuning', 'Instruction tuning', '', '', ARRAY['instruction tuning','instruct tuning','instruction fine-tuning']::text[], 'Core', 'Fine-tuning a base model on example commands and good responses so it learns to follow directions.', 'Like taking a brilliant but literal new hire and running them through orientation until they reliably do what you ask, how you ask.', 'A base model is trained on thousands of “instruction → ideal answer” pairs, turning raw text prediction into a usable assistant.', '[{"text":"A form of supervised fine-tuning.","id":"sft"},{"text":"Applied after pretraining.","id":"pretraining"},{"text":"Usually before RLHF.","id":"rlhf"}]'::jsonb, 'Pretraining leaves a model good at continuing text but not at obeying requests; instruction tuning fixes that with supervised examples of instructions paired with desired outputs. It’s usually the first alignment step, often followed by preference tuning like RLHF or DPO. It’s what converts a base model into something that answers questions instead of just autocompleting them.', 'The step that makes a model act like an assistant; without it, even a huge model feels unusable.', 'Supervised fine-tuning on (instruction, response) pairs to induce instruction-following before preference optimization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('sft', 'Supervised fine-tuning', 'Supervised Fine-Tuning', '“S-F-T”', ARRAY['supervised fine-tuning','sft']::text[], 'Core', 'Training a model on labeled input-output examples to teach it a specific behavior or format.', 'Like showing an apprentice hundreds of worked problems with the correct answers until they reproduce the method.', 'You collect 5,000 “customer message → ideal reply” pairs and fine-tune so the model matches your support tone exactly.', '[{"text":"The general case is fine-tuning.","id":"finetuning"},{"text":"Includes instruction tuning.","id":"instructiontuning"},{"text":"Complemented by RLHF.","id":"rlhf"}]'::jsonb, 'SFT is the straightforward flavor of fine-tuning: given inputs paired with the right outputs, minimize the error between prediction and target. It’s the backbone of instruction tuning and most task-specific adaptation. Its limits: it teaches imitation of the examples, so it can only be as good as the labeled data and can’t easily learn from “this is better than that” comparisons — which is where preference methods come in.', 'The most direct way to shape behavior when you have clean examples of exactly what you want.', 'Standard supervised learning on (input, target) pairs; the imitation step preceding preference optimization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('alignment', 'Alignment', '', '', ARRAY['alignment','ai alignment','aligned']::text[], 'Core', 'The work of making a model’s behavior match human intentions and values, not just its literal training objective.', 'Like the gap between a genie granting your exact words and one granting what you actually meant — alignment is aiming for the second.', 'A model that refuses to help build a weapon but happily explains chemistry safely is showing alignment between capability and intent.', '[{"text":"Pursued via RLHF.","id":"rlhf"},{"text":"Also pursued via Constitutional AI.","id":"constitutionalai"},{"text":"A defense against reward hacking in the reward model.","id":"rewardmodel"}]'::jsonb, 'Alignment spans everything from surface manners to deep safety: the model should be helpful, honest, and harmless, and should pursue what we want rather than a proxy that merely correlates with it. Techniques like RLHF, DPO, and constitutional methods are practical alignment tools. The hard part is that we often can’t fully specify our own values, and optimizing a proxy can drift in unintended ways — the core worry as models get more capable.', 'The difference between a model that’s smart and one that’s trustworthy; it’s a product requirement, not an afterthought.', 'Making learned behavior track intended goals/values rather than a mis-specified proxy objective.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('lora', 'LoRA', 'Low-Rank Adaptation', '“LOR-uh”', ARRAY['lora','low-rank adaptation']::text[], 'Rising', 'A cheap way to fine-tune by training tiny add-on matrices instead of the model’s billions of weights.', 'Like adding sticky notes to a reference book instead of reprinting the whole thing — small, removable, and you can keep several sets.', 'You adapt a 7B model to legal writing by training a few million LoRA parameters on one GPU, leaving the base weights untouched.', '[{"text":"A form of PEFT.","id":"peft"},{"text":"A kind of adapter.","id":"adapter"},{"text":"Its memory-frugal variant is QLoRA.","id":"qlora"}]'::jsonb, 'LoRA freezes the original weights and learns small low-rank matrices that adjust each layer’s behavior, cutting trainable parameters by orders of magnitude. This slashes memory and cost, and the adapters are swappable — one base model, many specialties. It usually matches full fine-tuning on narrow tasks, though it can lag on the most demanding adaptations.', 'Why custom models got affordable — train a tiny adapter, keep dozens of “personalities” on one base.', 'Injects trainable low-rank matrices into frozen layers; drastically fewer trainable params, mergeable at inference.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('qlora', 'QLoRA', 'Quantized Low-Rank Adaptation', '“Q-LOR-uh”', ARRAY['qlora','quantized lora']::text[], 'Rising', 'LoRA on a compressed model, so you can fine-tune a large model on a single consumer GPU.', 'Like renovating a house after shrinking your tools to fit a small van — you lose almost nothing but suddenly it all fits in your garage.', 'A researcher fine-tunes a 65B model on one 24GB GPU by quantizing the base to 4-bit and training LoRA adapters on top.', '[{"text":"A memory-saving take on LoRA.","id":"lora"},{"text":"A form of PEFT.","id":"peft"}]'::jsonb, 'QLoRA quantizes the frozen base model to 4-bit to shrink its memory footprint, then trains LoRA adapters in higher precision on top. The quantized weights stay fixed, so the precision loss barely hurts, while memory drops enough to fine-tune huge models on modest hardware. It democratized large-model fine-tuning, moving it from data centers to enthusiasts’ desks.', 'The reason fine-tuning big models stopped requiring a server farm — huge for cost and accessibility.', '4-bit quantized frozen base + higher-precision LoRA adapters; large memory savings with near-full-precision quality.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('peft', 'PEFT', 'Parameter-Efficient Fine-Tuning', '“PEFT”', ARRAY['peft','parameter-efficient fine-tuning']::text[], 'Rising', 'A family of methods that adapt a model by training a small slice of parameters, not the whole thing.', 'Like customizing a car with bolt-on accessories instead of rebuilding the engine — cheaper, reversible, and you keep the original.', 'A team uses PEFT to spin up ten task-specific variants of one base model, each adding only a few megabytes of trained parameters.', '[{"text":"Includes LoRA.","id":"lora"},{"text":"Also includes adapters.","id":"adapter"},{"text":"Contrast with full fine-tuning.","id":"finetuning"}]'::jsonb, 'PEFT is the umbrella over techniques — LoRA, adapters, prompt tuning — that freeze most of the model and train only a small set of new or selected parameters. This cuts compute, memory, and storage, and makes adaptations portable and stackable. It rarely beats full fine-tuning on the hardest tasks, but it wins overwhelmingly on cost and flexibility, which is why it dominates practical tuning.', 'The category that made custom models routine — small, swappable, cheap adaptations of one shared base.', 'Umbrella for methods training a small parameter subset atop a frozen model (LoRA, adapters, prompt tuning).', 'Training', 60, ARRAY['seed','training']::text[]),
  ('adapter', 'Adapter', '', '', ARRAY['adapter','adapter module','adapter layers']::text[], 'Core', 'A small trainable module slipped between a frozen model’s layers to teach it a new skill.', 'Like plug-in expansion cards for a computer — the machine stays the same; you add a card for the new capability.', 'You insert adapter modules into a frozen base model and train just those to specialize it for medical text.', '[{"text":"A form of PEFT.","id":"peft"},{"text":"Closely related to LoRA.","id":"lora"}]'::jsonb, 'Adapters add small bottleneck layers inside the network and train only them while the base stays frozen, making adaptation cheap and modular. Different adapters can be swapped in for different tasks on the same shared model. LoRA is a close relative that adapts existing weights rather than inserting new layers; both fall under PEFT.', 'Modular skills for one base model — mix and match without retraining the whole thing.', 'Inserted bottleneck modules trained while the backbone is frozen; a PEFT approach, kin to LoRA.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('distillation', 'Distillation', '', '', ARRAY['distillation','model distillation']::text[], 'Core', 'Compressing a big model’s know-how into a smaller one that mimics its behavior.', 'Like boiling a rich stock down to a concentrated cube — far smaller, most of the flavor kept.', 'A large model’s answers train a compact model that runs ten times faster while behaving nearly the same on everyday tasks.', '[{"text":"The detailed form is knowledge distillation.","id":"knowledgedistillation"},{"text":"Uses a student model.","id":"studentmodel"},{"text":"Guided by a teacher model.","id":"teachermodel"}]'::jsonb, 'Distillation trains a small student to reproduce a large teacher’s outputs — its predictions or full probability distributions — packing more signal into fewer parameters than training from scratch. The payoff is speed, cost, and on-device deployment; the ceiling is the teacher, whose mistakes and biases the student inherits. It’s the standard bridge from a frontier model to a shippable small one.', 'How you turn an expensive model into a cheap, fast one that’s good enough for most requests.', 'Train a compact student to match a teacher’s outputs/soft targets; smaller and faster, capped by the teacher.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('knowledgedistillation', 'Knowledge distillation', '', '', ARRAY['knowledge distillation','kd']::text[], 'Core', 'Distillation done by matching the teacher’s full confidence spread, not just its final answers.', 'Like learning from a mentor who not only gives the answer but tells you how sure they were about each option — the near-misses teach you too.', 'A student trains on the teacher’s soft probabilities (“80% cat, 15% dog, 5% fox”), absorbing nuance a hard “cat” label would hide.', '[{"text":"The core method within distillation.","id":"distillation"},{"text":"Produces a student model.","id":"studentmodel"}]'::jsonb, 'Classic knowledge distillation, from Hinton and colleagues, trains the student on the teacher’s softened output distribution rather than one-hot labels. Those “soft targets” carry dark knowledge — the relative likelihoods across wrong answers — which conveys more than a single correct label. This lets small models learn faster and generalize better than training on hard labels alone.', 'The technique behind small models that punch above their weight; the teacher’s uncertainty is part of the lesson.', 'Train the student on the teacher’s soft (temperature-scaled) output distribution; soft targets carry extra signal.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('continuedpretraining', 'Continued pretraining', '', '', ARRAY['continued pretraining','continual pretraining','domain-adaptive pretraining']::text[], 'Rising', 'Keeping the pretraining going on a new corpus so a model soaks up a fresh domain or language.', 'Like sending a well-read generalist to live in a new field for a year — same person, now fluent in the local dialect and specifics.', 'A general model gets continued pretraining on a big pile of legal documents so it internalizes legal language before any fine-tuning.', '[{"text":"Extends pretraining.","id":"pretraining"},{"text":"Risks catastrophic forgetting.","id":"catastrophicforgetting"},{"text":"Broader than fine-tuning.","id":"finetuning"}]'::jsonb, 'Rather than task-specific fine-tuning, continued pretraining runs the same self-supervised objective on additional domain data to broadly shift the model’s knowledge. It’s useful for specialized fields, new languages, or fresher data. The main hazard is catastrophic forgetting — pushing too hard on new data can erode the general abilities the base model started with, so data mixing and careful rates matter.', 'How you make a model natively fluent in your domain — deeper than fine-tuning, but riskier and pricier.', 'Additional self-supervised pretraining on new-domain data; balances adaptation against catastrophic forgetting.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('catastrophicforgetting', 'Catastrophic forgetting', '', '', ARRAY['catastrophic forgetting','catastrophic interference']::text[], 'Core', 'When training a model on something new makes it abruptly lose skills it already had.', 'Like cramming for a new language so hard that last year’s subject leaks out of your head entirely.', 'You fine-tune a model heavily on legal text and suddenly it’s worse at basic math it used to handle easily.', '[{"text":"A danger of continued pretraining.","id":"continuedpretraining"},{"text":"Also a risk in fine-tuning.","id":"finetuning"},{"text":"Mitigated by PEFT.","id":"peft"}]'::jsonb, 'Neural networks store knowledge in shared weights, so updating them for a new task can overwrite the patterns that supported old ones. It’s a central obstacle to sequential learning and aggressive fine-tuning. Mitigations include mixing old data back in, freezing parts of the network, using PEFT so the base stays intact, or regularizing weights to resist large changes.', 'Why fine-tuning can quietly degrade a model elsewhere — always test the skills you didn’t train on.', 'Overwriting of prior representations during new-task training; countered by rehearsal, freezing, PEFT, or regularization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('syntheticdata', 'Synthetic data', '', '', ARRAY['synthetic data','generated data','model-generated data']::text[], 'Rising', 'Training data made by a model rather than collected from the real world.', 'Like a flight simulator generating endless practice scenarios so pilots don’t need a real storm to train on.', 'A strong model writes thousands of math problems with worked solutions, and those become training data for a smaller model.', '[{"text":"A source for supervised fine-tuning.","id":"sft"},{"text":"Often produced by a teacher model.","id":"teachermodel"},{"text":"A form of data augmentation.","id":"dataaugmentation"}]'::jsonb, 'Synthetic data lets teams manufacture examples where real data is scarce, private, or expensive, and to target specific weaknesses. Used well, it boosts capability cheaply; used carelessly, it risks model collapse — training on a model’s own averaged output can erode diversity and amplify its errors over generations. Quality control and grounding in real data are the guardrails.', 'A powerful way to cover gaps and rare cases — but data made by models can quietly inbreed if you’re not careful.', 'Model-generated training examples; scalable but risks distribution collapse without real-data anchoring/filtering.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('dataaugmentation', 'Data augmentation', '', '', ARRAY['data augmentation','augmentation']::text[], 'Core', 'Expanding a dataset by making tweaked copies of what you already have.', 'Like practicing a recipe with slight variations each time — different pans, small substitutions — so you can cook it in any kitchen.', 'A vision model’s training images get flipped, cropped, and recolored, multiplying the dataset and teaching robustness.', '[{"text":"Reduces overfitting.","id":"overfitting"},{"text":"Improves generalization.","id":"generalization"},{"text":"Overlaps with synthetic data.","id":"syntheticdata"}]'::jsonb, 'Augmentation transforms existing examples in label-preserving ways — rotations for images, paraphrases or back-translation for text — to increase variety without collecting new data. It reduces overfitting and improves generalization by exposing the model to more surface variation. The catch: transformations that change the true label, or that don’t reflect real-world variation, teach the wrong lesson.', 'A cheap robustness boost from data you already own — squeeze more learning from every example.', 'Label-preserving transformations that expand data variety; curbs overfitting, improves generalization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('labeling', 'Labeling', '', '', ARRAY['labeling','labelling','data labeling']::text[], 'Core', 'Attaching the correct answer to each training example so a model can learn from it.', 'Like a teacher writing the right answer beside each practice problem before handing the worksheet to a student.', 'Reviewers tag ten thousand emails as “spam” or “not spam” so a classifier has ground truth to learn from.', '[{"text":"Closely tied to annotation.","id":"annotation"},{"text":"The fuel for supervised learning.","id":"supervisedlearning"}]'::jsonb, 'Supervised learning needs examples paired with target outputs, and labeling is the human-heavy process of producing them. It’s often the costliest, slowest part of a project, and label quality caps model quality — noisy or inconsistent labels teach noise. Guidelines, multiple raters, and agreement checks are how teams keep labels trustworthy.', 'Usually the real bottleneck in an ML project — slow, expensive, and quality-limiting.', 'Assigning target outputs to examples for supervised training; label noise directly bounds achievable accuracy.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('annotation', 'Annotation', '', '', ARRAY['annotation','data annotation','annotator']::text[], 'Core', 'Marking up data with the extra information a model needs to learn — labels, spans, boxes, rankings.', 'Like a copy editor marking a manuscript: highlighting names, flagging sections, noting what’s what for whoever reads it next.', 'Annotators draw boxes around every pedestrian in dashcam frames so a detection model knows what to find.', '[{"text":"A superset of labeling.","id":"labeling"},{"text":"Often done with HITL.","id":"hitl"}]'::jsonb, 'Annotation is the broader craft around labeling: not just a class, but bounding boxes, entity spans, relationships, or preference rankings, guided by detailed instructions. Clear guidelines and inter-annotator agreement matter because ambiguous tasks yield inconsistent data. It’s where much of a dataset’s cost and quality is decided, well before any model runs.', 'The unglamorous work that determines whether your data is worth training on at all.', 'Enriching raw data with structured labels/markup per guidelines; consistency measured via inter-annotator agreement.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('datacontamination', 'Data contamination', '', '', ARRAY['data contamination','test set contamination','benchmark contamination']::text[], 'Rising', 'When test questions leak into training data, so a model’s scores look better than its real ability.', 'Like a student who secretly saw the exam beforehand — the perfect grade tells you nothing about what they actually learned.', 'A benchmark’s questions turn up in the web-scraped training set, and the model “aces” them by recall, not reasoning.', '[{"text":"Fought with deduplication.","id":"deduplication"},{"text":"Undermines evals.","id":"evals"},{"text":"A hazard in pretraining.","id":"pretraining"}]'::jsonb, 'Because pretraining scrapes huge swaths of the web, public benchmarks often end up inside the training data, inflating evaluation scores. It’s a major reason leaderboard numbers can mislead and why fresh, held-out, or private test sets matter. Detecting it is hard — you’re looking for overlap in trillions of tokens — so teams increasingly favor recently-created or canary-marked benchmarks.', 'Why you shouldn’t trust a shiny benchmark number at face value — the test may have leaked into training.', 'Overlap between eval and training data inflating metrics; mitigated by held-out/fresh/canary test sets and dedup.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('deduplication', 'Deduplication', '', '', ARRAY['deduplication','dedup','dedupe']::text[], 'Core', 'Removing repeated or near-identical examples from a dataset before training.', 'Like clearing duplicate photos off your phone so one over-shared meme doesn’t crowd out your actual memories.', 'A web crawl has the same article mirrored a thousand times; dedup keeps one copy so the model doesn’t over-weight it.', '[{"text":"Reduces data contamination.","id":"datacontamination"},{"text":"Also reduces overfitting.","id":"overfitting"},{"text":"Cleans data for pretraining.","id":"pretraining"}]'::jsonb, 'Large corpora are full of exact and near-duplicate text, and training on repeats wastes compute, encourages memorization, and can worsen contamination. Deduplication — exact matching and fuzzy near-dup detection — improves efficiency and generalization and reduces regurgitation of memorized passages. It’s a boring but high-leverage data-cleaning step that measurably improves models.', 'A cheap data-hygiene step that makes models train faster and memorize less — quietly important.', 'Exact/near-duplicate removal from corpora; cuts memorization and contamination, improves training efficiency.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('curriculumlearning', 'Curriculum learning', '', '', ARRAY['curriculum learning','curriculum training']::text[], 'Core', 'Training a model on easy examples first, then gradually harder ones — like a school syllabus.', 'Like teaching arithmetic before calculus: the early, simple lessons build the footing the hard ones stand on.', 'A code model trains first on short, simple snippets, then longer and trickier programs as it improves.', '[{"text":"A strategy within training.","id":"training"},{"text":"Shapes the learning signal.","id":"learningsignal"}]'::jsonb, 'Curriculum learning orders training data from simple to complex so early, easy signal builds representations that make later, hard examples learnable. It can speed convergence and improve final quality, echoing how people learn. The tricky parts are defining “difficulty” and pacing the ramp — a badly designed curriculum can help little or even hurt versus plain random ordering.', 'Sometimes teaching order matters — structuring the data can beat throwing everything in at once.', 'Ordering training examples easy→hard to ease optimization; benefit depends on a good difficulty measure and pacing.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('selfsupervisedlearning', 'Self-supervised learning', 'Self-Supervised Learning', '“S-S-L”', ARRAY['self-supervised learning','ssl','self-supervision']::text[], 'Core', 'Learning from raw data by hiding part of it and predicting the missing piece — no human labels needed.', 'Like learning a language by covering the last word of sentences you read and guessing it, over and over.', 'Predicting the next token across trillions of words is self-supervised: the text itself provides the “answer.”', '[{"text":"The engine of pretraining.","id":"pretraining"},{"text":"Contrast with supervised learning.","id":"supervisedlearning"},{"text":"Also contrast with unsupervised learning.","id":"unsupervisedlearning"}]'::jsonb, 'Self-supervised learning invents its own labels from the structure of the data — next-token prediction, masked-word filling — so it can train on unlabeled corpora at massive scale. This is the trick that made pretraining possible: the internet becomes training data without anyone labeling it. It gives models broad general knowledge, which supervised fine-tuning then shapes toward specific behavior.', 'The breakthrough that let models learn from the whole internet without armies of labelers.', 'Supervision derived from the data itself (e.g. next-token/masked prediction); enables label-free pretraining at scale.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('unsupervisedlearning', 'Unsupervised learning', '', '', ARRAY['unsupervised learning','unsupervised']::text[], 'Core', 'Finding structure in data with no labels — the model discovers patterns on its own.', 'Like sorting a pile of mixed photos into natural groups without anyone telling you the categories.', 'A clustering algorithm groups customers into segments from their behavior, with no predefined labels to learn from.', '[{"text":"Contrast with supervised learning.","id":"supervisedlearning"},{"text":"Overlaps with self-supervised learning.","id":"selfsupervisedlearning"}]'::jsonb, 'Unsupervised learning uncovers hidden structure — clusters, densities, low-dimensional representations — without target outputs. Classic examples are k-means clustering and dimensionality reduction. It overlaps with self-supervised learning, but the distinction is subtle: self-supervision manufactures prediction targets from the data, while pure unsupervised methods seek structure without any prediction target at all.', 'Useful when you have lots of data but no labels — it finds groupings and structure to act on.', 'Learning structure (clusters/manifolds) without labels or targets; distinct from self-supervised prediction tasks.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('supervisedlearning', 'Supervised learning', '', '', ARRAY['supervised learning','supervised']::text[], 'Core', 'Learning from examples where each input comes with the correct answer.', 'Like studying with an answer key — you check each attempt against the right answer and adjust.', 'Training a model to detect fraud from thousands of transactions each already marked “fraud” or “legit.”', '[{"text":"Needs labeling.","id":"labeling"},{"text":"Contrast with unsupervised learning.","id":"unsupervisedlearning"},{"text":"Also contrast with reinforcement learning.","id":"reinforcementlearning"}]'::jsonb, 'Supervised learning is the classic setup: given labeled input-output pairs, learn a mapping that predicts the output for new inputs. It’s the most direct and well-understood paradigm, powering classification and regression everywhere. Its bottleneck is labels — they’re expensive to produce and their quality caps performance, which is exactly why self-supervised pretraining became so attractive.', 'The dependable default when you have labeled data; its cost lives in getting those labels.', 'Learn input→output from labeled pairs (classification/regression); performance bounded by label quantity and quality.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('reinforcementlearning', 'Reinforcement learning', 'Reinforcement Learning', '“R-L”', ARRAY['reinforcement learning','rl']::text[], 'Core', 'Learning by trial and error, guided by rewards for good actions and penalties for bad ones.', 'Like training a dog with treats and “no” — behavior that earns reward gets repeated, behavior that doesn’t fades.', 'An agent learns to play a game by trying moves and getting points, gradually favoring the actions that win.', '[{"text":"The basis of RLHF.","id":"rlhf"},{"text":"Contrast with supervised learning.","id":"supervisedlearning"}]'::jsonb, 'Instead of labeled answers, RL gives an agent rewards for the outcomes of its actions, and it learns a policy that maximizes cumulative reward over time. The hard parts are delayed rewards (which action deserves credit?) and exploration versus exploitation. In language models, RL powers alignment: RLHF optimizes the model against a reward model trained on human preferences.', 'The paradigm behind alignment tuning and agents — useful when success is a signal, not a labeled answer.', 'Learn a policy maximizing cumulative reward via trial and error; credit assignment and exploration are core challenges.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('semisupervisedlearning', 'Semi-supervised learning', '', '', ARRAY['semi-supervised learning','semi-supervised']::text[], 'Core', 'Learning from a small labeled set plus a large pile of unlabeled data.', 'Like a teacher grading a few papers in detail, then trusting students to learn the rest from patterns in the unmarked stack.', 'You label 1,000 medical images and let the model exploit 100,000 unlabeled ones to sharpen its understanding.', '[{"text":"Blends supervised learning.","id":"supervisedlearning"},{"text":"Blended with unsupervised learning.","id":"unsupervisedlearning"}]'::jsonb, 'Semi-supervised learning bridges supervised and unsupervised: a little labeled data anchors the task while abundant unlabeled data reveals structure that improves generalization. Techniques include pseudo-labeling and consistency training. It shines when labels are scarce or costly but raw data is plentiful — a very common real-world situation.', 'The pragmatic middle path when labeling everything is too expensive but you have plenty of raw data.', 'Combines limited labels with large unlabeled data (pseudo-labels/consistency) to improve over supervised-only.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('transferlearning', 'Transfer learning', '', '', ARRAY['transfer learning','transfer']::text[], 'Core', 'Reusing what a model learned on one task to jump-start a related one.', 'Like a guitarist picking up the ukulele fast — the fingers already know most of what they need.', 'A model pretrained on general text is fine-tuned on legal documents, reaching good accuracy with far less legal data.', '[{"text":"Underlies fine-tuning.","id":"finetuning"},{"text":"Builds on pretraining.","id":"pretraining"},{"text":"Related to multitask learning.","id":"multitasklearning"}]'::jsonb, 'Transfer learning takes representations learned on a large, general task and adapts them to a new, often smaller task, saving data and compute. It’s the whole logic of the pretrain-then-fine-tune era: learn broadly once, specialize cheaply many times. It works because low-level features (grammar, edges, structure) generalize; it can falter when source and target domains are too dissimilar.', 'The reason you rarely start from scratch — borrow a strong base and specialize for a fraction of the cost.', 'Adapt representations from a source task to a target task; the foundation of the pretrain→fine-tune paradigm.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('multitasklearning', 'Multitask learning', '', '', ARRAY['multitask learning','multi-task learning','mtl']::text[], 'Core', 'Training one model on several tasks at once so they reinforce each other.', 'Like a decathlete whose sprint training also helps their long jump — skills share a common base and lift together.', 'A single model is trained to translate, summarize, and answer questions, and gets better at each than if trained alone.', '[{"text":"Related to transfer learning.","id":"transferlearning"},{"text":"Also related to meta-learning.","id":"metalearning"}]'::jsonb, 'Multitask learning shares parameters across related tasks, letting the model learn common structure and regularize itself, often improving each task and data efficiency. The risk is negative transfer — conflicting tasks can drag each other down — and balancing their losses is fiddly. Modern instruction-tuned models are effectively massively multitask, trained on many task types together.', 'One model that does many things can be cheaper and stronger than many narrow ones — if the tasks play nicely.', 'Joint training on multiple tasks with shared parameters; shared structure helps, but negative transfer can hurt.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('metalearning', 'Meta-learning', '', '', ARRAY['meta-learning','meta learning','learning to learn']::text[], 'Rising', 'Training a model to get good at learning new tasks quickly, not just at one task.', 'Like a student who has learned how to study, so each new subject clicks faster than the last.', 'A meta-learned model adapts to a brand-new classification task from just a handful of examples, having practiced adapting many times.', '[{"text":"Related to few-shot learning.","id":"fewshotlearning"},{"text":"Also related to in-context learning.","id":"incontextlearning"}]'::jsonb, 'Meta-learning — “learning to learn” — trains across many tasks so the model acquires a strategy for fast adaptation, rather than mastering a single task. Approaches range from optimization-based methods that find easily-fine-tuned initializations to models that adapt in-context. It’s the formal cousin of what large models do when they pick up a task from a few prompt examples.', 'The idea behind models that adapt fast to new tasks with little data — flexibility as a trained skill.', 'Optimize across a task distribution for rapid adaptation; kin to in-context few-shot behavior in large models.', 'Training', 60, ARRAY['seed','training']::text[]),
  ('fewshotlearning', 'Few-shot learning', '', '', ARRAY['n-shot learning','few-shot classification']::text[], 'Core', 'The training goal of learning a new task from just a handful of labeled examples.', 'Like recognizing a new bird species after seeing two or three photos, because you already understand what makes birds differ.', 'A model trained for few-shot learning classifies a new category correctly after seeing only five labeled samples of it.', '[{"text":"Often achieved via meta-learning.","id":"metalearning"},{"text":"The inference-time analog is few-shot.","id":"fewshot"}]'::jsonb, 'As a training paradigm, few-shot learning targets sample efficiency: build a model that generalizes to new classes or tasks from very little data, usually via meta-learning or strong pretrained representations. It’s distinct from in-context few-shot prompting, which achieves a similar effect at inference without weight updates. Both chase the same prize — doing more with fewer examples.', 'The ambition of “learn from almost nothing,” valuable wherever labeled data is scarce.', 'Learning to generalize from k examples per class, typically via meta-learning or pretrained features; the training-time analog of in-context few-shot.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('gradientdescent', 'Gradient descent', '', '', ARRAY['gradient descent','gd']::text[], 'Core', 'The optimization method that repeatedly nudges weights downhill to shrink the loss.', 'Like walking downhill in fog by always stepping in the steepest downward direction until you reach the valley.', 'Each training step, the model computes how wrong it is, then adjusts every weight a little in the direction that reduces the error.', '[{"text":"Follows the gradient.","id":"gradient"},{"text":"The scalable version is stochastic gradient descent.","id":"sgd"},{"text":"Run by the optimizer.","id":"optimizer"}]'::jsonb, 'Gradient descent iteratively updates parameters in the opposite direction of the loss gradient, scaled by a learning rate, to find a minimum. Plain (batch) gradient descent uses the whole dataset per step, which is accurate but slow; that impracticality at scale is why stochastic variants took over. It’s the fundamental optimization engine under nearly all neural network training.', 'The core mechanic of “the model learned” — countless tiny downhill steps on an error surface.', 'Iterative param update opposite the loss gradient, scaled by learning rate; full-batch form is the baseline for SGD.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('sgd', 'Stochastic gradient descent', 'Stochastic Gradient Descent', '“S-G-D”', ARRAY['stochastic gradient descent','sgd']::text[], 'Core', 'Gradient descent that updates using small random batches instead of the whole dataset, for speed.', 'Like adjusting a recipe after each small tasting rather than cooking the entire banquet before your first tweak.', 'Instead of processing all million examples per step, the model updates weights after each batch of 32, taking many more, faster steps.', '[{"text":"A scalable form of gradient descent.","id":"gradientdescent"},{"text":"Each update processes one batch size of examples.","id":"batchsize"},{"text":"Refined by Adam.","id":"adam"}]'::jsonb, 'SGD estimates the gradient from a random mini-batch, making each step cheap and frequent; the noise it adds can even help escape shallow bad minima. It converges far faster in wall-clock time than full-batch descent on large data, at the cost of a noisier path. It’s the practical backbone of deep learning, and modern optimizers like Adam are refinements of it.', 'The reason training on huge datasets is even feasible — cheap, frequent updates instead of one giant one.', 'Gradient descent on random mini-batches; cheaper, noisier steps that scale to large data and aid escaping minima.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('backpropagation', 'Backpropagation', 'Backpropagation', '“backprop”', ARRAY['backpropagation','backprop','back-propagation']::text[], 'Core', 'The algorithm that figures out how much each weight contributed to the error, so it can be corrected.', 'Like tracing a factory defect back through the assembly line to see which station caused it, and by how much.', 'After a wrong prediction, backprop pushes the error signal backward layer by layer, giving each weight its share of the blame.', '[{"text":"Computes the gradient.","id":"gradient"},{"text":"Used by gradient descent.","id":"gradientdescent"},{"text":"To reduce the loss function.","id":"lossfunction"}]'::jsonb, 'Backpropagation applies the chain rule from calculus to compute the gradient of the loss with respect to every weight efficiently, in a single backward pass through the network. It’s what makes training deep networks tractable — without it, computing all those derivatives would be hopeless. Paired with an optimizer, it’s the mechanism that turns “the model was wrong” into concrete weight updates.', 'The math that makes learning possible at all; you rarely touch it, but every trained model depends on it.', 'Chain-rule computation of loss gradients w.r.t. all params in one backward pass; feeds the optimizer.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('lossfunction', 'Loss function', '', '', ARRAY['loss function','loss','cost function']::text[], 'Core', 'The formula that scores how wrong the model is, giving training something to minimize.', 'Like a golf score — the lower the number, the better you’re doing, and every swing aims to bring it down.', 'A model’s loss on a batch is high when its predictions miss the targets; training keeps pushing that number lower.', '[{"text":"A common one is cross-entropy.","id":"crossentropy"},{"text":"What gradient descent minimizes.","id":"gradientdescent"},{"text":"The broader term is objective function.","id":"objectivefunction"}]'::jsonb, 'The loss function turns the gap between predictions and targets into a single number that optimization minimizes. Its choice defines what “good” means — cross-entropy for classification, mean-squared error for regression, custom losses for special goals. Because the model optimizes exactly what you measure, a poorly chosen loss produces a model that’s technically great at the wrong thing.', 'You get the behavior you measure — the loss encodes your definition of success, so choose it carefully.', 'Scalar objective quantifying prediction error; its gradient drives all weight updates. Choice defines the target behavior.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('objectivefunction', 'Objective function', '', '', ARRAY['objective function','objective','criterion']::text[], 'Core', 'The quantity training tries to optimize — usually minimizing loss, sometimes maximizing reward.', 'Like the scoreboard a whole team plays toward — everything they do is in service of moving that one number the right way.', 'In supervised training the objective is to minimize loss; in RL it’s to maximize expected reward.', '[{"text":"A minimize-case is the loss function.","id":"lossfunction"},{"text":"In RL it’s the reward from the reward model.","id":"rewardmodel"},{"text":"May include regularization.","id":"regularization"}]'::jsonb, 'The objective function is the general term for what optimization targets; a loss function is the common minimize-this special case, while reinforcement learning maximizes an objective like expected return. It also often bundles in regularization terms that trade raw fit against simplicity. Whatever it is, the model will optimize it literally — which is why mis-specified objectives are a core source of surprising, unwanted behavior.', 'The single thing your model is truly trying to do; if it’s wrong, no amount of data fixes it.', 'The optimized quantity (loss to minimize or reward to maximize), possibly with regularizers; literally optimized, so specify carefully.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('learningrate', 'Learning rate', 'Learning Rate', '“L-R”', ARRAY['learning rate','lr','step size']::text[], 'Core', 'The size of the step training takes each time it adjusts the weights.', 'Like your stride walking downhill in fog — tiny steps are safe but slow; huge leaps are fast but you might overshoot the valley.', 'Set the learning rate too high and the loss bounces around or explodes; too low and training crawls for days.', '[{"text":"Scales each gradient descent step.","id":"gradientdescent"},{"text":"Varied by a learning rate schedule.","id":"lrschedule"},{"text":"Ramped by warmup.","id":"warmup"}]'::jsonb, 'The learning rate scales how far each weight moves along the gradient per step, and it’s often the single most important hyperparameter. Too large and training diverges or oscillates; too small and it’s painfully slow or gets stuck. Because no single value is ideal throughout, most training uses a schedule that changes it over time, often with a warmup and decay.', 'The dial most likely to make or break a training run — worth tuning before almost anything else.', 'Scalar scaling the gradient step; the dominant hyperparameter, usually varied via a schedule with warmup/decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('lrschedule', 'Learning rate schedule', '', '', ARRAY['learning rate schedule','lr schedule','learning rate scheduler']::text[], 'Core', 'A plan for changing the learning rate during training instead of holding it fixed.', 'Like driving: accelerate gently from a stop, cruise, then ease off as you approach your exit.', 'Training warms up the rate for the first few hundred steps, holds it, then decays it smoothly toward zero near the end.', '[{"text":"Controls the learning rate.","id":"learningrate"},{"text":"Includes a warmup.","id":"warmup"},{"text":"Used across training.","id":"training"}]'::jsonb, 'A schedule varies the learning rate over the course of training — common shapes include linear warmup followed by cosine or linear decay. Early warmup avoids destabilizing the fresh weights; later decay lets the model settle into a good minimum with smaller, finer steps. The right schedule can noticeably improve final quality and stability over any single fixed rate.', 'A quiet lever on final model quality — how you ramp and cool the learning rate matters.', 'Time-varying learning rate (e.g. warmup + cosine/linear decay); improves stability and final convergence.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('warmup', 'Warmup', '', '', ARRAY['warmup','warm-up','learning rate warmup']::text[], 'Core', 'Starting training with a small learning rate and ramping it up over the first steps.', 'Like stretching before a sprint — ease in so you don’t pull something at full speed from a cold start.', 'For the first 500 steps the learning rate climbs from near zero to its target, so early updates don’t blow up the model.', '[{"text":"The opening phase of a learning rate schedule.","id":"lrschedule"},{"text":"Protects the learning rate.","id":"learningrate"},{"text":"Important for AdamW.","id":"adamw"}]'::jsonb, 'At the start of training the weights are fresh and gradients can be large and erratic, so jumping straight to a high learning rate risks divergence. Warmup ramps the rate up gradually, letting the optimizer’s statistics and the weights stabilize before full-speed learning. It’s especially important for large models and adaptive optimizers, and is usually the front half of a full schedule.', 'A small safeguard that prevents big training runs from destabilizing in their fragile first moments.', 'Gradual learning-rate ramp over initial steps to stabilize early training; typically precedes decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('batchsize', 'Batch size', '', '', ARRAY['batch size','minibatch size','mini-batch']::text[], 'Core', 'How many examples the model looks at before making one weight update.', 'Like how many quiz answers you grade before adjusting your teaching — a few gives quick but jumpy feedback, many gives a steadier read.', 'A batch size of 256 means the model averages the error over 256 examples, then takes one optimization step.', '[{"text":"Defines each stochastic gradient descent update.","id":"sgd"},{"text":"Stretched by gradient accumulation.","id":"gradientaccumulation"},{"text":"Interacts with learning rate.","id":"learningrate"}]'::jsonb, 'Batch size trades gradient quality against speed and memory: larger batches give smoother, more reliable gradient estimates and use hardware efficiently, but need more memory and can generalize slightly worse. Smaller batches are noisier but sometimes find better minima. It interacts tightly with the learning rate — change one and you often must retune the other.', 'A core cost-and-quality knob; it’s bounded by your GPU memory and coupled to the learning rate.', 'Examples per gradient update; larger = smoother gradients + more memory, coupled to learning rate; extendable via accumulation.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('epoch', 'Epoch', '', '', ARRAY['epoch','epochs','training epoch']::text[], 'Core', 'One full pass of the model through the entire training dataset.', 'Like reading a whole textbook cover to cover once — an epoch is one complete read-through.', 'Training for three epochs means the model sees every example in the dataset three times.', '[{"text":"Composed of many iterations.","id":"iteration"},{"text":"Too many risks overfitting.","id":"overfitting"}]'::jsonb, 'An epoch is one complete sweep over all training data, made up of many iterations (one per batch). Too few epochs and the model underfits; too many and it starts memorizing and overfitting. Large-scale pretraining often runs less than a single epoch over a giant corpus, since seeing that much data even once is plenty — the concept matters most for smaller fine-tuning runs.', 'A rough dial on how long to train; more isn’t always better, since extra passes invite overfitting.', 'One full pass over the dataset (many iterations); count trades underfitting vs. overfitting.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('iteration', 'Iteration', '', '', ARRAY['iteration','training step','step']::text[], 'Core', 'A single weight update — one batch processed and one step taken.', 'Like a single stir of the pot: one small adjustment, repeated thousands of times to get the dish right.', 'With 10,000 examples and a batch size of 100, one epoch is 100 iterations.', '[{"text":"Many make up an epoch.","id":"epoch"},{"text":"Each does one stochastic gradient descent step.","id":"sgd"},{"text":"Sized by the batch size.","id":"batchsize"}]'::jsonb, 'An iteration (or step) is the atomic unit of training: process one batch, compute the loss and gradient, and update the weights once. The number of iterations equals dataset size divided by batch size, times the number of epochs. Progress and learning-rate schedules are usually tracked in steps, which is why training dashboards count iterations, not epochs.', 'The granular unit training is measured in — loss curves and schedules move step by step.', 'One batch → one gradient update; steps = (dataset/batch) × epochs; the unit for schedules and logging.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('optimizer', 'Optimizer', '', '', ARRAY['optimizer','optimiser']::text[], 'Core', 'The algorithm that decides exactly how to update weights from the gradients each step.', 'Like a hiking guide who takes the “downhill” reading and decides the actual footing — pace, momentum, and where to place each step.', 'You switch the optimizer from plain SGD to AdamW and the model trains faster and more stably on the same data.', '[{"text":"Consumes the gradient.","id":"gradient"},{"text":"A simple one is stochastic gradient descent.","id":"sgd"},{"text":"A popular one is AdamW.","id":"adamw"}]'::jsonb, 'The optimizer turns raw gradients into weight updates, often adding momentum and per-parameter adaptive step sizes to speed and stabilize training. Choices range from simple SGD with momentum to adaptive methods like Adam and AdamW, each with its own hyperparameters. It’s a major determinant of training speed and final quality, and it works hand in hand with the learning rate schedule.', 'A behind-the-scenes choice that shapes how fast and reliably a model trains.', 'Maps gradients to parameter updates (momentum, adaptive rates); e.g. SGD, Adam, AdamW; paired with an LR schedule.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('adam', 'Adam', 'Adaptive Moment Estimation', '“ADD-um”', ARRAY['adam','adam optimizer']::text[], 'Core', 'A popular optimizer that gives each weight its own adaptive step size, so training just works more often.', 'Like cruise control that also adjusts for each hill and curve — it adapts the pace per situation instead of one fixed speed.', 'A team reaches for Adam as the default optimizer because it trains reliably across many models with little tuning.', '[{"text":"A kind of optimizer.","id":"optimizer"},{"text":"Improves on stochastic gradient descent.","id":"sgd"},{"text":"Refined by AdamW.","id":"adamw"}]'::jsonb, 'Adam combines momentum (a running average of past gradients) with per-parameter scaling based on recent gradient magnitudes, so parameters with small or noisy gradients still move sensibly. This adaptivity makes it robust and fast with minimal tuning, which is why it became a default. Its main quirk is how it handles weight decay, which the AdamW variant fixes.', 'The dependable default optimizer — it trains most models well without fuss.', 'Momentum + per-parameter adaptive step sizes from first/second gradient moments; robust default, superseded by AdamW for decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('adamw', 'AdamW', 'Adam with decoupled Weight decay', '“ADD-um-double-you”', ARRAY['adamw','adam w']::text[], 'Core', 'A fixed-up version of Adam that handles weight decay correctly — now the standard for training big models.', 'Like the same trusty cruise control after a recall fixed a subtle wiring bug — same idea, but it behaves the way it should.', 'Most large language models are trained with AdamW because its weight decay generalizes better than plain Adam’s.', '[{"text":"Fixes Adam.","id":"adam"},{"text":"The decay term is weight decay.","id":"weightdecay"},{"text":"Paired with warmup.","id":"warmup"}]'::jsonb, 'In original Adam, weight decay got entangled with the adaptive scaling, weakening its regularizing effect. AdamW decouples weight decay from the gradient update so it acts as intended, improving generalization. That subtle correction made it the default optimizer for transformer and large-model training, usually paired with a warmup-and-decay learning rate schedule.', 'The optimizer behind most modern large models; a small fix that meaningfully helps generalization.', 'Adam with decoupled weight decay; standard for transformer/LLM training, typically with warmup + decay.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('weightdecay', 'Weight decay', '', '', ARRAY['weight decay','l2 regularization','l2 penalty']::text[], 'Core', 'Gently shrinking weights toward zero during training so the model stays simple and generalizes.', 'Like a tidy-desk rule that quietly clears clutter each day, keeping only what earns its place.', 'Adding weight decay stops a model from letting a few weights grow huge to memorize training quirks.', '[{"text":"A form of regularization.","id":"regularization"},{"text":"Reduces overfitting.","id":"overfitting"},{"text":"Decoupled in AdamW.","id":"adamw"}]'::jsonb, 'Weight decay penalizes large weights, nudging all of them slightly toward zero each step, which discourages the model from fitting noise and improves generalization. It’s closely related to L2 regularization, though how it’s applied differs between plain Adam and AdamW. Set too high it underfits by over-simplifying; too low and it barely helps — it’s a standard, mild regularizer in almost every training recipe.', 'A quiet guard against overfitting that’s in nearly every training recipe.', 'Penalty shrinking weights toward zero (≈ L2); improves generalization, decoupled in AdamW.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('regularization', 'Regularization', '', '', ARRAY['regularization','regularisation','regularizer']::text[], 'Core', 'Any technique that keeps a model from over-memorizing so it generalizes to new data.', 'Like a coach who stops you from over-optimizing your form for one practice court, so your game holds up anywhere.', 'Dropout, weight decay, and data augmentation are all regularization — each fights overfitting a different way.', '[{"text":"Includes weight decay.","id":"weightdecay"},{"text":"Also includes dropout.","id":"dropout"},{"text":"Improves generalization.","id":"generalization"}]'::jsonb, 'Regularization is the umbrella for methods that constrain a model’s effective complexity to improve generalization: penalties on weights, dropout, early stopping, augmentation, and more. The goal is to shift the balance from fitting the training set toward performing on unseen data. Too much and the model underfits; the art is finding the sweet spot for your data size and task.', 'The family of tricks that make a model work in the real world, not just on its training set.', 'Techniques constraining effective capacity (weight decay, dropout, early stopping, augmentation) to improve generalization.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('gradientclipping', 'Gradient clipping', '', '', ARRAY['gradient clipping','grad clipping','clip gradients']::text[], 'Core', 'Capping how big a gradient step can be, so one wild update doesn’t wreck the model.', 'Like a governor on an engine that prevents it from redlining and blowing up on a sudden surge.', 'A rare huge gradient would send the loss to infinity, but clipping caps its size and training keeps going smoothly.', '[{"text":"Tames the gradient.","id":"gradient"},{"text":"Stabilizes gradient descent.","id":"gradientdescent"},{"text":"Guards the learning rate.","id":"learningrate"}]'::jsonb, 'Occasionally gradients explode — becoming enormous — and a single unclipped step can push weights into garbage, spiking the loss to NaN. Gradient clipping bounds the gradient’s norm (or value) before the update, keeping training stable through rough patches. It’s cheap insurance widely used in training deep and recurrent networks, especially with high learning rates or long sequences.', 'A stability safeguard that keeps long, expensive training runs from suddenly falling apart.', 'Bounds gradient norm/value before the update to prevent explosions; standard for stability in deep/recurrent training.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('gradientaccumulation', 'Gradient accumulation', '', '', ARRAY['gradient accumulation','grad accumulation']::text[], 'Core', 'Summing gradients over several small batches before updating, to fake a bigger batch than memory allows.', 'Like filling a big order in several small trips because your cart is tiny — you still deliver the full load, just in pieces.', 'Your GPU fits only 8 examples, but you accumulate over 32 mini-batches to update as if the batch size were 256.', '[{"text":"Simulates a larger batch size.","id":"batchsize"},{"text":"Defers the optimizer step.","id":"optimizer"},{"text":"Spreads one step across iterations.","id":"iteration"}]'::jsonb, 'When the desired batch size won’t fit in memory, gradient accumulation runs several forward-backward passes, adds up their gradients, and applies one optimizer step, simulating a large effective batch. This lets modest hardware train with the stability benefits of big batches, trading time for memory. The effective batch size is the per-step batch times the accumulation count.', 'How you get big-batch training on small hardware — trading wall-clock time for memory you don’t have.', 'Accumulate gradients over N micro-batches, then one optimizer step; effective batch = micro-batch × N.', 'Training', 80, ARRAY['seed','training']::text[])
